"""Typed session-scoped workflow continuity for the Concierge route team."""

from __future__ import annotations

import json
from dataclasses import asdict, dataclass, field
from datetime import UTC, datetime
from typing import Any, Literal, TypedDict

from agents.concierge.constants import (
    REGISTERED_WORKFLOW_OWNERS,
    WORKFLOW_STATE_SESSION_KEY,
)

WorkflowStatus = Literal["active", "paused", "complete"]
WorkflowAction = Literal["set_active", "update_active", "pause_active", "complete_active"]


class WorkflowStateError(ValueError):
    """Invalid workflow owner, status, or transition."""


@dataclass(slots=True)
class ActiveWorkflow:
    owner: str
    status: WorkflowStatus
    goal: str
    resume_hint: str = ""
    last_user_visible_event: str = ""
    updated_at: str = ""

    def __post_init__(self) -> None:
        if self.owner not in REGISTERED_WORKFLOW_OWNERS:
            raise WorkflowStateError(f"unknown workflow owner: {self.owner!r}")
        if self.status not in ("active", "paused", "complete"):
            raise WorkflowStateError(f"invalid workflow status: {self.status!r}")
        if not self.goal.strip():
            raise WorkflowStateError("workflow goal is required")


@dataclass(slots=True)
class PausedWorkflow:
    owner: str
    goal: str
    resume_hint: str = ""

    def __post_init__(self) -> None:
        if self.owner not in REGISTERED_WORKFLOW_OWNERS:
            raise WorkflowStateError(f"unknown workflow owner: {self.owner!r}")
        if not self.goal.strip():
            raise WorkflowStateError("paused workflow goal is required")


@dataclass(slots=True)
class LastCompletedWorkflow:
    owner: str
    goal: str
    outcome: str
    recommended_next_steps: list[str] = field(default_factory=list)

    def __post_init__(self) -> None:
        if self.owner not in REGISTERED_WORKFLOW_OWNERS:
            raise WorkflowStateError(f"unknown workflow owner: {self.owner!r}")
        if not self.goal.strip():
            raise WorkflowStateError("completed workflow goal is required")
        if not self.outcome.strip():
            raise WorkflowStateError("completed workflow outcome is required")


@dataclass(slots=True)
class WorkflowState:
    active_workflow: ActiveWorkflow | None = None
    paused_workflows: list[PausedWorkflow] = field(default_factory=list)
    last_completed_workflow: LastCompletedWorkflow | None = None

    def to_dict(self) -> dict[str, Any]:
        return _drop_none(asdict(self))

    @classmethod
    def from_dict(cls, data: dict[str, Any] | None) -> WorkflowState:
        if not data:
            return cls()
        active_raw = data.get("active_workflow")
        active = ActiveWorkflow(**active_raw) if isinstance(active_raw, dict) else None
        paused = [
            PausedWorkflow(**item)
            for item in data.get("paused_workflows") or []
            if isinstance(item, dict)
        ]
        completed_raw = data.get("last_completed_workflow")
        completed = (
            LastCompletedWorkflow(**completed_raw) if isinstance(completed_raw, dict) else None
        )
        return cls(
            active_workflow=active,
            paused_workflows=paused,
            last_completed_workflow=completed,
        )


class WorkflowStatePatch(TypedDict, total=False):
    action: WorkflowAction
    owner: str
    status: WorkflowStatus
    goal: str
    resume_hint: str
    last_user_visible_event: str
    outcome: str
    recommended_next_steps: list[str]


def _utc_now_iso() -> str:
    return datetime.now(UTC).replace(microsecond=0).isoformat()


def _drop_none(data: dict[str, Any]) -> dict[str, Any]:
    out: dict[str, Any] = {}
    for key, value in data.items():
        if value is None:
            continue
        if isinstance(value, list) and not value:
            if key == "paused_workflows":
                out[key] = []
            continue
        out[key] = value
    return out


class WorkflowStateStore:
    """Read and update workflow continuity stored on Agno session_state."""

    session_key: str = WORKFLOW_STATE_SESSION_KEY

    @classmethod
    def read(cls, session_state: dict[str, Any] | None) -> WorkflowState:
        if not session_state:
            return WorkflowState()
        raw = session_state.get(cls.session_key)
        if isinstance(raw, str):
            try:
                raw = json.loads(raw)
            except json.JSONDecodeError:
                return WorkflowState()
        if not isinstance(raw, dict):
            return WorkflowState()
        try:
            return WorkflowState.from_dict(raw)
        except WorkflowStateError:
            return WorkflowState()

    @classmethod
    def write(cls, session_state: dict[str, Any], state: WorkflowState) -> None:
        session_state[cls.session_key] = state.to_dict()

    @classmethod
    def format_for_instructions(cls, state: WorkflowState) -> str:
        if (
            state.active_workflow is None
            and not state.paused_workflows
            and state.last_completed_workflow is None
        ):
            return "No active, paused, or recently completed workflows."
        return json.dumps(state.to_dict(), indent=2)

    @classmethod
    def apply_patch(
        cls,
        session_state: dict[str, Any],
        patch: WorkflowStatePatch,
    ) -> WorkflowState:
        state = cls.read(session_state)
        action = patch.get("action")
        if not action:
            raise WorkflowStateError("action is required")

        if action == "set_active":
            state = cls._set_active(state, patch)
        elif action == "update_active":
            state = cls._update_active(state, patch)
        elif action == "pause_active":
            state = cls._pause_active(state, patch)
        elif action == "complete_active":
            state = cls._complete_active(state, patch)
        else:
            raise WorkflowStateError(f"unknown workflow action: {action!r}")

        cls.write(session_state, state)
        return state

    @classmethod
    def _set_active(cls, state: WorkflowState, patch: WorkflowStatePatch) -> WorkflowState:
        owner = _require_str(patch, "owner")
        status = patch.get("status", "active")
        goal = _require_str(patch, "goal")
        active = ActiveWorkflow(
            owner=owner,
            status=status,
            goal=goal,
            resume_hint=patch.get("resume_hint", ""),
            last_user_visible_event=patch.get("last_user_visible_event", ""),
            updated_at=_utc_now_iso(),
        )
        return WorkflowState(
            active_workflow=active,
            paused_workflows=state.paused_workflows,
            last_completed_workflow=state.last_completed_workflow,
        )

    @classmethod
    def _update_active(cls, state: WorkflowState, patch: WorkflowStatePatch) -> WorkflowState:
        active = state.active_workflow
        if active is None:
            raise WorkflowStateError("no active workflow to update")
        owner = patch.get("owner")
        if owner is not None and owner != active.owner:
            raise WorkflowStateError(
                f"cannot update active workflow owned by {active.owner!r} as {owner!r}"
            )
        if "status" in patch and patch["status"] is not None:
            active.status = patch["status"]
        if "goal" in patch and patch["goal"] is not None:
            goal = patch["goal"].strip()
            if not goal:
                raise WorkflowStateError("workflow goal is required")
            active.goal = goal
        if "resume_hint" in patch:
            active.resume_hint = patch.get("resume_hint") or ""
        if "last_user_visible_event" in patch:
            active.last_user_visible_event = patch.get("last_user_visible_event") or ""
        active.updated_at = _utc_now_iso()
        return WorkflowState(
            active_workflow=active,
            paused_workflows=state.paused_workflows,
            last_completed_workflow=state.last_completed_workflow,
        )

    @classmethod
    def _pause_active(cls, state: WorkflowState, patch: WorkflowStatePatch) -> WorkflowState:
        active = state.active_workflow
        if active is None:
            raise WorkflowStateError("no active workflow to pause")
        owner = patch.get("owner")
        if owner is not None and owner != active.owner:
            raise WorkflowStateError(
                f"cannot pause workflow owned by {active.owner!r} as {owner!r}"
            )
        paused_entry = PausedWorkflow(
            owner=active.owner,
            goal=active.goal,
            resume_hint=active.resume_hint or patch.get("resume_hint", ""),
        )
        paused = [p for p in state.paused_workflows if p.owner != active.owner]
        paused.append(paused_entry)
        active.status = "paused"
        active.updated_at = _utc_now_iso()
        return WorkflowState(
            active_workflow=active,
            paused_workflows=paused,
            last_completed_workflow=state.last_completed_workflow,
        )

    @classmethod
    def _complete_active(cls, state: WorkflowState, patch: WorkflowStatePatch) -> WorkflowState:
        active = state.active_workflow
        if active is None:
            raise WorkflowStateError("no active workflow to complete")
        owner = patch.get("owner")
        if owner is not None and owner != active.owner:
            raise WorkflowStateError(
                f"cannot complete workflow owned by {active.owner!r} as {owner!r}"
            )
        outcome = _require_str(patch, "outcome")
        steps = patch.get("recommended_next_steps") or []
        completed = LastCompletedWorkflow(
            owner=active.owner,
            goal=active.goal,
            outcome=outcome,
            recommended_next_steps=[s.strip() for s in steps if s.strip()],
        )
        paused = [p for p in state.paused_workflows if p.owner != active.owner]
        return WorkflowState(
            active_workflow=None,
            paused_workflows=paused,
            last_completed_workflow=completed,
        )


def _require_str(patch: WorkflowStatePatch, key: str) -> str:
    value = patch.get(key)  # type: ignore[literal-required]
    if not isinstance(value, str) or not value.strip():
        raise WorkflowStateError(f"{key} is required")
    return value.strip()

"""Workflow state update tool for Concierge specialist members."""

from __future__ import annotations

from typing import Literal

from agno.run.base import RunContext
from agno.tools.decorator import tool
from agno.tools.toolkit import Toolkit

from agents.concierge.constants import UPDATE_WORKFLOW_STATE_TOOL
from agents.concierge.workflow_state import (
    WorkflowState,
    WorkflowStateError,
    WorkflowStatePatch,
    WorkflowStateStore,
)


def _session(run_context: RunContext) -> dict:
    if run_context.session_state is None:
        run_context.session_state = {}
    return run_context.session_state


@tool(
    name=UPDATE_WORKFLOW_STATE_TOOL,
    description=(
        "Update Concierge workflow continuity for this session. "
        "action: set_active (start/replace), update_active (patch fields on active), "
        "pause_active (keep sticky owner, status paused), complete_active (terminal — "
        "requires outcome). owner must be provisioner-agent. goal required for set_active."
    ),
    requires_confirmation=False,
    stop_after_tool_call=False,
)
def update_workflow_state(
    run_context: RunContext,
    action: Literal["set_active", "update_active", "pause_active", "complete_active"],
    owner: str = "provisioner-agent",
    status: Literal["active", "paused", "complete"] = "active",
    goal: str = "",
    resume_hint: str = "",
    last_user_visible_event: str = "",
    outcome: str = "",
    recommended_next_steps: list[str] | None = None,
) -> dict[str, object]:
    patch: WorkflowStatePatch = {
        "action": action,
        "owner": owner,
        "status": status,
        "goal": goal,
        "resume_hint": resume_hint,
        "last_user_visible_event": last_user_visible_event,
        "outcome": outcome,
    }
    if recommended_next_steps is not None:
        patch["recommended_next_steps"] = recommended_next_steps
    try:
        state = WorkflowStateStore.apply_patch(_session(run_context), patch)
    except WorkflowStateError as exc:
        return {"ok": False, "error": str(exc)}
    return {"ok": True, "workflow_state": state.to_dict()}


concierge_workflow_toolkit = Toolkit(
    name="concierge_workflow_tools",
    tools=[update_workflow_state],
    add_instructions=False,
)

"""Fetch Concierge team prompts from Langfuse."""

from __future__ import annotations

import re

from agents.concierge.constants import (
    PRODUCT_INFO_PROMPT_NAME,
    PRODUCT_ROUTING_FRAME_PROMPT_NAME,
)
from agents.concierge.settings import ConciergeSettings
from agents.langfuse_prompts import (
    LangfusePromptClient,
    get_langfuse_client,
    prompt_text,
    resolve_prompt_options,
)

_LANGFUSE_PROMPT_REF = re.compile(
    r"@@@langfusePrompt:name=([^|]+)\|label=([^@]+)@@@",
)


def resolve_langfuse_prompt_references(
    body: str,
    client: LangfusePromptClient,
    *,
    label: str | None = None,
    cache_ttl_seconds: int | None = None,
) -> str:
    """Replace ``@@@langfusePrompt:...@@@`` markers with fetched sub-prompt bodies."""

    opts = resolve_prompt_options(label=label, cache_ttl_seconds=cache_ttl_seconds)

    def replacer(match: re.Match[str]) -> str:
        name = match.group(1).strip()
        ref_label = match.group(2).strip() or opts.label
        return prompt_text(
            client,
            name,
            label=ref_label,
            cache_ttl_seconds=opts.cache_ttl_seconds,
        )

    return _LANGFUSE_PROMPT_REF.sub(replacer, body)


def fetch_langfuse_prompt(
    client: LangfusePromptClient,
    name: str,
    *,
    settings: ConciergeSettings | None = None,
    label: str | None = None,
    cache_ttl_seconds: int | None = None,
    resolve_references: bool = True,
) -> str:
    opts = resolve_prompt_options(label=label, cache_ttl_seconds=cache_ttl_seconds)
    body = prompt_text(
        client,
        name,
        label=opts.label,
        cache_ttl_seconds=opts.cache_ttl_seconds,
        variables=_prompt_variables(settings) if settings else None,
    )
    if resolve_references and _LANGFUSE_PROMPT_REF.search(body):
        body = resolve_langfuse_prompt_references(
            body,
            client,
            label=opts.label,
            cache_ttl_seconds=opts.cache_ttl_seconds,
        )
    return body


def fetch_router_prompt_for_settings(settings: ConciergeSettings) -> str:
    client = get_langfuse_client(
        public_key=settings.langfuse_public_key,
        secret_key=settings.langfuse_secret_key,
        base_url=settings.langfuse_base_url,
    )
    return fetch_langfuse_prompt(
        client,
        settings.router_langfuse_prompt_name,
        settings=settings,
    )


def fetch_product_guide_prompt_for_settings(settings: ConciergeSettings) -> str:
    client = get_langfuse_client(
        public_key=settings.langfuse_public_key,
        secret_key=settings.langfuse_secret_key,
        base_url=settings.langfuse_base_url,
    )
    return fetch_langfuse_prompt(
        client,
        settings.product_guide_langfuse_prompt_name,
        settings=settings,
    )


def fetch_product_routing_frame(client: LangfusePromptClient) -> str:
    opts = resolve_prompt_options()
    return prompt_text(
        client,
        PRODUCT_ROUTING_FRAME_PROMPT_NAME,
        label=opts.label,
        cache_ttl_seconds=opts.cache_ttl_seconds,
    )


def fetch_product_info(client: LangfusePromptClient) -> str:
    opts = resolve_prompt_options()
    return prompt_text(
        client,
        PRODUCT_INFO_PROMPT_NAME,
        label=opts.label,
        cache_ttl_seconds=opts.cache_ttl_seconds,
    )


def _prompt_variables(settings: ConciergeSettings) -> dict[str, str]:
    return {
        "default_terminal_url": settings.default_terminal_url,
        "demo_terminal_base_url": settings.demo_terminal_base_url.rstrip("/"),
    }

"""Post-run streaming helpers for the Concierge route team."""

from __future__ import annotations

import json
import uuid
from collections.abc import AsyncIterator
from typing import Any, cast

from agno.agent import Agent
from agno.models.message import Message
from agno.models.response import ModelResponse, ToolExecution
from agno.run.agent import RunOutput as AgentRunOutput
from agno.run.agent import ToolCallCompletedEvent, ToolCallStartedEvent
from agno.run.team import RunCompletedEvent, RunEvent, RunOutputEvent
from agno.team import Team

from agents.concierge.constants import PRODUCT_INFO_PROMPT_NAME
from agents.concierge.langfuse_prompts import fetch_langfuse_prompt
from agents.concierge.render_tools import (
    PRIMARY_RENDER_TOOL_NAMES,
    RENDER_SUGGESTED_PROMPTS_TOOL,
    render_suggested_prompts,
)
from agents.concierge.settings import ConciergeSettings
from agents.concierge.workflow_state import WorkflowState, WorkflowStateStore
from agents.langfuse_prompts import get_langfuse_client

_NUM_SUGGESTED_PROMPTS = 3
_FALLBACK_PRODUCT_SUGGESTIONS = (
    "What can RebaseAI do for my repo?",
    "Set up a dev environment for a GitHub repo",
    "How do PM and Coder agents coordinate?",
)


def _tool_names(tools: list[ToolExecution] | None) -> set[str]:
    if not tools:
        return set()
    return {name for t in tools if (name := t.tool_name)}


def _collect_tool_names(completion: RunCompletedEvent) -> set[str]:
    names = _tool_names(completion.tools)
    for response in completion.member_responses or []:
        if isinstance(response, AgentRunOutput):
            names |= _tool_names(response.tools)
        else:
            member_tools = getattr(response, "tools", None)
            names |= _tool_names(member_tools)
    return names


def should_inject_suggested_prompts(completion: RunCompletedEvent) -> bool:
    names = _collect_tool_names(completion)
    if RENDER_SUGGESTED_PROMPTS_TOOL in names:
        return False
    if names & PRIMARY_RENDER_TOOL_NAMES and not completion.content:
        return False
    return bool(completion.content)


def workflow_completed_this_turn(
    *,
    state_before: WorkflowState,
    state_after: WorkflowState,
) -> bool:
    if state_after.last_completed_workflow is None:
        return False
    before = state_before.last_completed_workflow
    after = state_after.last_completed_workflow
    if after is None:
        return False
    if before is None:
        return True
    return (
        before.owner != after.owner
        or before.goal != after.goal
        or before.outcome != after.outcome
    )


def should_inject_product_completion_suggestions(
    completion: RunCompletedEvent,
    *,
    state_before: WorkflowState,
) -> bool:
    if RENDER_SUGGESTED_PROMPTS_TOOL in _collect_tool_names(completion):
        return False
    state_after = WorkflowStateStore.read(completion.session_state)
    return workflow_completed_this_turn(state_before=state_before, state_after=state_after)


def _build_suggested_prompt_messages(
    *,
    user_message: str,
    assistant_content: str,
    system_prompt: str,
) -> list[Message]:
    return [
        Message(role="system", content=system_prompt),
        Message(
            role="user",
            content=(
                f"User message:\n{user_message}\n\n"
                f"Assistant response:\n{assistant_content}\n\n"
                f"Generate exactly {_NUM_SUGGESTED_PROMPTS} follow-up suggestions."
            ),
        ),
    ]


def _parse_suggested_prompts_response(model_response: ModelResponse) -> list[str] | None:
    from agno.run.agent import Followups

    followups_obj: Followups | None = None
    if model_response.parsed is not None:
        if isinstance(model_response.parsed, Followups):
            followups_obj = model_response.parsed
        elif isinstance(model_response.parsed, dict):
            try:
                followups_obj = Followups.model_validate(model_response.parsed)
            except Exception:
                followups_obj = None
    if followups_obj is None and model_response.content:
        try:
            followups_obj = Followups.model_validate(json.loads(model_response.content))
        except Exception:
            return None
    if followups_obj is None:
        return None
    suggestions = [s.strip() for s in followups_obj.suggestions if s.strip()]
    return suggestions[:_NUM_SUGGESTED_PROMPTS] if suggestions else None


async def generate_suggested_prompts(
    model_source: Agent | Team,
    *,
    user_message: str,
    assistant_content: str,
    system_prompt: str,
) -> list[str]:
    model = model_source.model
    if model is None:
        return list(_FALLBACK_PRODUCT_SUGGESTIONS)

    from agno.agent._response import _get_followups_response_format

    try:
        model_response = await model.aresponse(
            messages=_build_suggested_prompt_messages(
                user_message=user_message,
                assistant_content=assistant_content,
                system_prompt=system_prompt,
            ),
            response_format=_get_followups_response_format(model),
        )
        prompts = _parse_suggested_prompts_response(model_response)
        if prompts and len(prompts) >= _NUM_SUGGESTED_PROMPTS:
            return prompts[:_NUM_SUGGESTED_PROMPTS]
    except Exception:
        return list(_FALLBACK_PRODUCT_SUGGESTIONS)
    return list(_FALLBACK_PRODUCT_SUGGESTIONS)


def _product_completion_system_prompt(
    settings: ConciergeSettings,
    state: WorkflowState,
) -> str:
    client = get_langfuse_client(
        public_key=settings.langfuse_public_key,
        secret_key=settings.langfuse_secret_key,
        base_url=settings.langfuse_base_url,
    )
    try:
        product_info = fetch_langfuse_prompt(
            client,
            PRODUCT_INFO_PROMPT_NAME,
            settings=settings,
            resolve_references=False,
        )
    except Exception:
        product_info = "RebaseAI product information is unavailable."

    completed = state.last_completed_workflow
    completed_block = ""
    if completed is not None:
        completed_block = (
            f"Last completed workflow: owner={completed.owner}, goal={completed.goal}, "
            f"outcome={completed.outcome}, recommended_next_steps={completed.recommended_next_steps}"
        )

    return (
        "Generate follow-up prompt chips after a workflow completed. Each suggestion must be a "
        "complete user message under 80 characters. Base suggestions on Product Info and the "
        "completed workflow only — not hidden specialist internals. Prefer natural next product "
        "steps (PM board, discovery, dev tools) when appropriate.\n\n"
        f"Product Info:\n{product_info}\n\n{completed_block}"
    )


def build_suggested_prompt_tool_events(
    completion: RunCompletedEvent,
    prompts: list[str],
) -> list[RunOutputEvent]:
    tool_call_id = str(uuid.uuid4())
    result = render_suggested_prompts.entrypoint(prompts=prompts)  # type: ignore[misc]
    tool = ToolExecution(
        tool_call_id=tool_call_id,
        tool_name=RENDER_SUGGESTED_PROMPTS_TOOL,
        tool_args={"prompts": prompts},
        result=json.dumps(result),
    )
    team_id = completion.team_id or ""
    team_name = completion.team_name or "RebaseAI Concierge"
    return [
        ToolCallStartedEvent(
            tool=tool,
            team_id=team_id,
            team_name=team_name,
            run_id=completion.run_id,
            session_id=completion.session_id,
        ),
        ToolCallCompletedEvent(
            tool=tool,
            content=result,
            team_id=team_id,
            team_name=team_name,
            run_id=completion.run_id,
            session_id=completion.session_id,
        ),
    ]


async def inject_suggested_prompts_stream(
    team: Team,
    response_stream: AsyncIterator[RunOutputEvent],
    *,
    user_message: str,
    settings: ConciergeSettings,
    workflow_state_before: WorkflowState,
) -> AsyncIterator[RunOutputEvent]:
    completion: RunCompletedEvent | None = None
    async for chunk in response_stream:
        if chunk.event == RunEvent.run_completed.value:
            completion = cast(RunCompletedEvent, chunk)
            continue
        yield chunk

    if completion is None:
        return

    prompts: list[str] | None = None
    if should_inject_product_completion_suggestions(
        completion,
        state_before=workflow_state_before,
    ):
        state_after = WorkflowStateStore.read(completion.session_state)
        prompts = await generate_suggested_prompts(
            team,
            user_message=user_message,
            assistant_content=str(completion.content or ""),
            system_prompt=_product_completion_system_prompt(settings, state_after),
        )
    elif should_inject_suggested_prompts(completion):
        prompts = await generate_suggested_prompts(
            team,
            user_message=user_message,
            assistant_content=str(completion.content or ""),
            system_prompt=(
                "Generate follow-up prompts for a RebaseAI concierge chat. Each suggestion "
                "must be a complete user message under 80 characters. Do not repeat the "
                "user's last message."
            ),
        )

    if prompts:
        for event in build_suggested_prompt_tool_events(completion, prompts):
            yield event

    yield completion


def wrap_concierge_team_arun(team: Team, *, settings: ConciergeSettings) -> None:
    """Wrap team arun so AGUI streaming returns an AsyncIterator with suggestion injection."""
    base_arun = team.arun

    def arun(*args: Any, **kwargs: Any) -> Any:
